<?php
namespace App\Repositories\Crm; use App\Enums\Crm\ProformaStatus; use App\Enums\UserRole; use App\Models\Crm\CrmProformaInvoice; use App\Models\User; use Illuminate\Contracts\Pagination\LengthAwarePaginator; use Illuminate\Database\Eloquent\Builder;
class ProformaRepository { public function paginate(User $u,array $f=[]):LengthAwarePaginator{return $this->query($u)->with('lead')->when($f['search']??null,fn(Builder $q,string $s)=>$q->where(fn(Builder $q)=>$q->where('proforma_number','like',"%$s%")->orWhere('customer_company','like',"%$s%")->orWhere('customer_name','like',"%$s%")->orWhere('customer_email','like',"%$s%")->orWhere('customer_phone','like',"%$s%")))->when($f['status']??null,fn(Builder $q,string $s)=>$q->where('status',$s))->latest()->paginate(12)->withQueryString();} public function find(User $u,int $id):CrmProformaInvoice{return $this->query($u)->with(['lead','customer','quotation','items','payments.recorder','shares.creator'])->findOrFail($id);} public function metrics(User $u):array{$q=$this->query($u);return ['total_value'=>(float)(clone $q)->sum('grand_total'),'pending_value'=>(float)(clone $q)->whereIn('status',[ProformaStatus::Sent->value,ProformaStatus::PartiallyPaid->value,ProformaStatus::Overdue->value])->sum('balance_amount'),'paid_month'=>(float)(clone $q)->whereHas('payments',fn(Builder $p)=>$p->whereBetween('payment_date',[now()->startOfMonth(),now()->endOfMonth()]))->sum('paid_amount'),'overdue'=>(clone $q)->where('due_date','<',today())->whereNotIn('status',[ProformaStatus::Paid->value,ProformaStatus::Cancelled->value])->count(),'partial'=>(clone $q)->where('status',ProformaStatus::PartiallyPaid->value)->count(),'latest'=>(clone $q)->latest()->limit(6)->get()];} private function query(User $u):Builder{return CrmProformaInvoice::query()->where('company_id',$u->company_id)->when(($u->role instanceof UserRole?$u->role:UserRole::tryFrom((string)$u->role))===UserRole::Sales,fn(Builder $q)=>$q->whereHas('lead',fn(Builder $l)=>$l->where('assigned_user_id',$u->id)));} }
